package main

import (
	"bufio"
	"fmt"
	"os"
	"strings"
	"strconv"
	"errors"
)

type Deque struct {
	data     []int
	front    int
	size     int
	capacity int
}
func (d *Deque)resize(newCap int){
	n := make([]int, newCap*2)

	for i := 0 ; i < d.size ;i++{
		n[i] = d.data[(d.front + i) % d.capacity]

	}
	d.front = 0
	d.capacity = d.capacity*2
		d.data = n

}   // dobra o tamanho do caso ele chege no máximo de sua capacidade
func (d *Deque)  PushBack(v int)  {
	if d.size == d.capacity{
		d.resize(d.capacity)
	}
    l := (d.front+d.size)%d.capacity  
	d.size++
	d.data[l] = v

}    // insere valor no fim
func (d *Deque)   PushFront(v int) {
	if d.size == d.capacity{
		d.resize(d.capacity)
	}
	l := (d.front - 1 + d.capacity)%d.capacity  

	d.data[l] = v
	d.front = l
	d.size++
}    // insere valor no início
func (d *Deque)  PopBack()  error    {
	if d.size == 0{

		return errors.New("fail: buffer vazio")
	}
	d.size--
	return nil
}      // remove valor do fim
func (d *Deque)  PopFront()  error   {
	if d.size == 0{

		return errors.New("fail: buffer vazio")
	}
	d.data[d.front] = 0
	d.front++
	d.size--
	return nil
}      // remove valor do início
func (d *Deque)  Front() (int, error){
	if d.size == 0{
		return 0 ,errors.New("fail: deque vazio")
	}//
	valor := d.data[d.front]
	return valor, nil
} // retorna o valor do início
func (d *Deque)   Back() (int, error) {
	valor := d.data[(d.front + d.size - 1) % d.capacity]
	if d.size == 0{
		return valor ,errors.New("fail: deque vazio")
	}//

	return valor, nil


} // retorna o valor do fim

func (d *Deque)   Clear()    {
	d.size = 0
	d.front = 0
}          // limpa todos os elementos
func (d *Deque)   Len() int  {
	return d.size
}          // retorna o número de elementos
  // representação no formato [1, 2, 3]
func (b *Deque) String() string {
	result := []string{}
	for i := range b.size {
		val := b.data[(b.front+i)%b.capacity]
		result = append(result, fmt.Sprint(val))
	}
	return "[" + strings.Join(result, ", ") + "]"
}

func (b *Deque) Debug() string {
	result := make([]string, b.capacity)
	for i, _ := range result {
		result[i] = " _"
		if i == b.front {
			result[i] = ">_"
		}
	}
	for i := range b.size {
		index := (b.front + i) % b.capacity
		val := b.data[index]
		prefix := " "
		if i == 0 {
			prefix = ">"
		}
		result[index] = fmt.Sprintf("%s%d", prefix, val)
	}
	return strings.Join(result, " |")
}

func main() {
	scanner := bufio.NewScanner(os.Stdin)
	buf := &Deque{data: make([]int, 4), capacity: 4}

	for {
		fmt.Print("$")
		if !scanner.Scan() {
			break
		}
		line := scanner.Text()
		fmt.Println(line)
		args := strings.Fields(line)

		if len(args) == 0 {
			continue
		}

		cmd := args[0]

		switch cmd {
		case "show":
			fmt.Println(buf.String())
		case "debug":
			fmt.Println(buf.Debug())
		case "size":
			 fmt.Println(buf.Len())
		case "push_back":
			 for _, v := range args[1:] {
			 	num, _ := strconv.Atoi(v)
			 	buf.PushBack(num)
			 }
		case "push_front":
			 for _, v := range args[1:] {
			 	num, _ := strconv.Atoi(v)
			 	buf.PushFront(num)
			 }
		case "pop_back":
			 if err := buf.PopBack(); err != nil {
				fmt.Println(err)
			 }
		case "pop_front":
			 if err := buf.PopFront(); err != nil {
			 	fmt.Println(err)
			 }
		case "front":
			 if val, err := buf.Front(); err != nil {
			 	fmt.Println(err)
			 } else {
			 	fmt.Println(val)
			}
		case "back":
			 if val, err := buf.Back(); err != nil {
			 	fmt.Println(err)
			 } else {
			 	fmt.Println(val)
			 }
		case "clear":
			 buf.Clear()
		case "end":
			return
		default:
			fmt.Println("fail: comando invalido")
		}
	}
}
